def normalize_calculation_mode(value: Optional[str]) -> str:
    mode = "" if value is None else str(value).strip().lower()
    if mode in {"", "warehouse", "supply", "поставка", "расчет поставки", "расчёт поставки"}:
        return "warehouse"
    if mode in {"supplier", "order", "заказ", "расчет заказа", "расчёт заказа", "supplier_order"}:
        return "supplier"
    raise ValueError(f"Неизвестный режим расчёта: {value}. Допустимо: supply / supplier")


CONFIG.calculation_mode = normalize_calculation_mode(CONFIG.calculation_mode)


