REGION_TO_GROUP: Dict[str, str] = build_region_to_group()


def log(msg: str) -> None:
    print(f"[{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}] {msg}", flush=True)


def normalize_text(value: object) -> str:
    if pd.isna(value):
        return ""
    return str(value).strip()



def normalize_supplier_article_key(value: object) -> str:
    s = normalize_text(value).upper()
    s = s.replace(" ", "")
    s = re.sub(r"_+", "/", s)
    s = re.sub(r"/+", "/", s)
    return s.strip("/")


def is_misstais_store(store_name: object) -> bool:
    name = normalize_text(store_name).upper().replace(" ", "").replace("-", "")
    return name in {"MISSTAIS", "MISSTAISWB", "MISSTAISВБ", "MISST", "MT", "МТ", "MISS", "TAIS"}


def resolve_article_1c_for_store(
    nmid: object,
    supplier_article: object,
    article_1c_map: Dict[str, str],
    cfg: AppConfig,
) -> str:
    supplier_article_norm = normalize_text(supplier_article)

    # Для MISSTAIS / МТ бизнес-правило: Артикул 1С = Артикул продавца / supplierArticle.
    # Маппинг nmId -> 1С для MISSTAIS не используем, чтобы не заполнять лист "МТ ВБ" чужими кодами.
    if is_misstais_store(cfg.store_name):
        return supplier_article_norm

    article_1c = normalize_text(article_1c_map.get(normalize_nmid(nmid), ""))
    if article_1c:
        return article_1c

    return supplier_article_norm


def month_key(dt: datetime) -> str:
    return dt.strftime("%Y-%m")


def end_of_month(dt: datetime) -> datetime:
    last_day = calendar.monthrange(dt.year, dt.month)[1]
    return dt.replace(day=last_day)


def parse_ddmmyy_date(text_value: str) -> Optional[datetime]:
    match = re.search(r"(\d{2})-(\d{2})-(\d{2,4})", text_value)
    if not match:
        return None
    day, month, year = map(int, match.groups())
    year += 2000 if year < 100 else 0
    try:
        return datetime(year, month, day)
    except ValueError:
        return None


def read_transit_sheet(storage: S3Storage, key: str) -> pd.DataFrame:
    file_bytes = storage.read_bytes(key)

    try:
        workbook = pd.read_excel(io.BytesIO(file_bytes), sheet_name=None, header=None)
    except Exception as exc:
        raise ValueError(f"Не удалось прочитать файл транзита {key}: {exc}") from exc

    if isinstance(workbook, dict):
        if "Основной заказ" in workbook:
            raw = workbook["Основной заказ"]
        else:
            raw = next(iter(workbook.values()))
    else:
        raw = workbook

    if raw is None or raw.empty:
        return pd.DataFrame()

    def build_headers(row_a: pd.Series, row_b: pd.Series) -> List[str]:
        headers: List[str] = []
        for a, b in zip(row_a.tolist(), row_b.tolist()):
            a_text = normalize_text(a)
            b_text = normalize_text(b)
            if a_text and b_text:
                headers.append(f"{a_text} | {b_text}")
            elif b_text:
                headers.append(b_text)
            elif a_text:
                headers.append(a_text)
            else:
                headers.append("")
        return headers

    has_second_header = False
    if len(raw) >= 2:
        second_row_values = [normalize_text(x).lower() for x in raw.iloc[1].tolist()]
        transit_markers = ("заказ мп", "заказ опт", "заказ ритейл", "заказ магнит", "pcs")
        has_second_header = any(any(marker in value for marker in transit_markers) for value in second_row_values)

    if has_second_header:
        headers = build_headers(raw.iloc[0], raw.iloc[1])
        df = raw.iloc[2:].copy()
        df.columns = headers
    else:
        df = raw.copy()
        df.columns = [normalize_text(c) or f"col_{idx}" for idx, c in enumerate(df.columns)]

    df = df.dropna(how="all").copy()
    return df


def parse_ddmmyyyy_range_from_key(key: str) -> Tuple[Optional[datetime], Optional[datetime]]:
    match = re.search(r"__(\d{2}\.\d{2}\.\d{4})-(\d{2}\.\d{2}\.\d{4})__", key)
    if not match:
        return None, None
    start = datetime.strptime(match.group(1), "%d.%m.%Y")
    end = datetime.strptime(match.group(2), "%d.%m.%Y")
    return start, end


def first_present_column(df: pd.DataFrame, patterns: Sequence[str]) -> Optional[str]:
    lowered = {str(c).strip().lower(): c for c in df.columns}
    for pattern in patterns:
        pattern = pattern.lower().strip()
        for low_name, original in lowered.items():
            if pattern in low_name:
                return original
    return None


def normalize_nmid(value: object) -> str:
    s = normalize_text(value)
    return s[:-2] if s.endswith(".0") else s


def normalize_warehouse(name: object) -> str:
    s = normalize_text(name)
    if not s:
        return ""

    direct = WAREHOUSE_ALIASES.get(s)
    if direct:
        return direct

    # WB периодически переименовывает склады СЗФО. Для расчёта поставки
    # все такие варианты канонизируем в один целевой склад — Склад Шушары.
    lowered = s.lower().replace("ё", "е")
    lowered = re.sub(r"\s+", " ", lowered)
    if any(marker in lowered for marker in NORTHWEST_WAREHOUSE_NAME_MARKERS):
        return NORTHWEST_TARGET_WAREHOUSE

    return s


def normalize_template_header(name: object) -> str:
    return normalize_text(name)


def floor_int(value: float) -> int:
    if pd.isna(value):
        return 0
    return int(math.floor(float(value)))


def ceil_int(value: float) -> int:
    if pd.isna(value):
        return 0
    return int(math.ceil(float(value)))


def parse_week_key_date(key: str) -> Optional[datetime]:
    match = re.search(r"_(\d{4}-W\d{2})\.xlsx$", key)
    if not match:
        return None
    year, week = match.group(1).split("-W")
    return datetime.fromisocalendar(int(year), int(week), 1)


def largest_remainder_allocation(total: int, weights: Dict[str, float], minimum_one_for_nonzero: bool = False) -> Dict[str, int]:
    keys = list(weights.keys())
    if total <= 0 or not keys:
        return {key: 0 for key in keys}

    clean = {k: max(float(v), 0.0) for k, v in weights.items()}
    if sum(clean.values()) == 0:
        equal = total // len(keys)
        rem = total - equal * len(keys)
        out = {k: equal for k in keys}
        for k in keys[:rem]:
            out[k] += 1
        return out

    base = {}
    reserved = 0
    if minimum_one_for_nonzero:
        for k, v in clean.items():
            if v > 0 and reserved < total:
                base[k] = 1
                reserved += 1
            else:
                base[k] = 0
    else:
        base = {k: 0 for k in keys}

    remaining = max(total - reserved, 0)
    total_weight = sum(clean.values())
    raw = {k: remaining * clean[k] / total_weight for k in keys}
    floored = {k: int(math.floor(raw[k])) for k in keys}
    out = {k: base[k] + floored[k] for k in keys}
    rest = total - sum(out.values())

    remainders = sorted(((raw[k] - floored[k], k) for k in keys), reverse=True)
    for _, k in remainders[:rest]:
        out[k] += 1

    return out


class S3Storage:
    def __init__(self, cfg: AppConfig):
        if not cfg.bucket_name or not cfg.access_key or not cfg.secret_key:
            raise ValueError("Не заданы параметры Object Storage. Поддерживаются env: WB_S3_BUCKET/WB_S3_ACCESS_KEY/WB_S3_SECRET_KEY или YC_BUCKET_NAME/YC_ACCESS_KEY_ID/YC_SECRET_ACCESS_KEY.")

        self.bucket = cfg.bucket_name
        self.s3 = boto3.client(
            "s3",
            endpoint_url=cfg.endpoint_url,
            aws_access_key_id=cfg.access_key,
            aws_secret_access_key=cfg.secret_key,
            region_name=cfg.region_name,
            config=BotoConfig(signature_version="s3v4", read_timeout=300, connect_timeout=60),
        )

    def list_keys(self, prefix: str) -> List[str]:
        keys: List[str] = []
        continuation_token = None

        while True:
            kwargs = {"Bucket": self.bucket, "Prefix": prefix, "MaxKeys": 1000}
            if continuation_token:
                kwargs["ContinuationToken"] = continuation_token

            resp = self.s3.list_objects_v2(**kwargs)
            keys.extend([obj["Key"] for obj in resp.get("Contents", [])])

            if not resp.get("IsTruncated"):
                break
            continuation_token = resp.get("NextContinuationToken")

        return keys

    def read_bytes(self, key: str) -> bytes:
        obj = self.s3.get_object(Bucket=self.bucket, Key=key)
        return obj["Body"].read()

    def read_excel(self, key: str, sheet_name: Optional[str] = None) -> pd.DataFrame:
        return pd.read_excel(io.BytesIO(self.read_bytes(key)), sheet_name=sheet_name)

    def download_file(self, key: str, local_path: str) -> str:
        Path(local_path).parent.mkdir(parents=True, exist_ok=True)
        Path(local_path).write_bytes(self.read_bytes(key))
        return local_path

    def upload_file(self, local_path: str, key: str) -> None:
        self.s3.upload_file(local_path, self.bucket, key)


def load_weekly_window(storage: S3Storage, prefix: str, run_date: datetime, lookback_days: int, expected_sheet: Optional[str] = None) -> pd.DataFrame:
    keys = storage.list_keys(prefix)
    if not keys:
        raise FileNotFoundError(f"В Object Storage не найдено файлов по префиксу: {prefix}")

    cutoff = run_date - timedelta(days=lookback_days + 21)
    selected = [(parse_week_key_date(k) or datetime.min, k) for k in keys if (parse_week_key_date(k) or datetime.min) >= cutoff]
    if not selected:
        selected = [(parse_week_key_date(k) or datetime.min, k) for k in keys]

    parts: List[pd.DataFrame] = []
    for _, key in sorted(selected, key=lambda x: x[0]):
        try:
            df = storage.read_excel(key, sheet_name=expected_sheet)
            if isinstance(df, dict):
                df = next(iter(df.values()))
            if not df.empty:
                parts.append(df)
                log(f"Загружен файл: {key}")
        except Exception as exc:
            log(f"⚠️ Не удалось прочитать {key}: {exc}")

    if not parts:
        raise ValueError(f"Не удалось прочитать ни одного файла по префиксу {prefix}")

    return pd.concat(parts, ignore_index=True)


def resolve_ratings_key(storage: S3Storage, cfg: AppConfig) -> Optional[str]:
    if cfg.ratings_key:
        return cfg.ratings_key

    week_str = cfg.run_date.strftime("%Y-W%V")
    patterns = [
        f"Неделя {week_str}.xlsx",
        f"Неделя_{week_str}.xlsx",
    ]

    for prefix_tpl in cfg.ratings_prefix_candidates:
        prefix = prefix_tpl.format(store=cfg.store_name)
        try:
            keys = storage.list_keys(prefix)
        except Exception:
            continue
        for key in keys:
            filename = key.split("/")[-1]
            if any(p == filename for p in patterns):
                return key
        week_keys = [k for k in keys if "Неделя" in k.split("/")[-1]]
        if week_keys:
            return sorted(week_keys)[-1]

    return None


def load_ratings_map(storage: S3Storage, cfg: AppConfig) -> Dict[str, float]:
    key = resolve_ratings_key(storage, cfg)
    if not key:
        log("⚠️ Файл с рейтингами не найден. Фильтр по рейтингу не будет применён.")
        return {}

    df = storage.read_excel(key)
    if isinstance(df, dict):
        df = next(iter(df.values()))

    cols = {str(c).strip().lower(): c for c in df.columns}
    nm_col = None
    rating_col = None

    for k, original in cols.items():
        if "артикул wb" in k or k == "nmid":
            nm_col = original
        if "рейтинг отзывов" in k:
            rating_col = original

    if nm_col is None or rating_col is None:
        log(f"⚠️ В файле рейтингов не найдены нужные колонки. Колонки: {list(df.columns)}")
        return {}

    tmp = df[[nm_col, rating_col]].copy()
    tmp["nmId"] = tmp[nm_col].map(normalize_nmid)
    tmp["review_rating"] = pd.to_numeric(tmp[rating_col], errors="coerce")
    tmp = tmp.dropna(subset=["nmId", "review_rating"])

    ratings = (
        tmp.groupby("nmId", as_index=False)
        .agg(review_rating=("review_rating", "max"))
    )

    log(f"Загружены рейтинги отзывов: {len(ratings):,} SKU из {key}")
    return dict(zip(ratings["nmId"], ratings["review_rating"]))


def load_orders(storage: S3Storage, cfg: AppConfig) -> pd.DataFrame:
    df = load_weekly_window(storage, cfg.orders_prefix_tpl.format(store=cfg.store_name), cfg.run_date, cfg.lookback_days, expected_sheet="Заказы")
    required = ["date", "warehouseName", "oblastOkrugName", "regionName", "supplierArticle", "nmId", "subject", "finishedPrice"]
    missing = [c for c in required if c not in df.columns]
    if missing:
        raise KeyError(f"В заказах отсутствуют обязательные колонки: {missing}")

    df = df.copy()
    df["date"] = pd.to_datetime(df["date"], errors="coerce").dt.normalize()
    df = df[(df["date"] >= (cfg.run_date - timedelta(days=cfg.lookback_days - 1))) & (df["date"] <= cfg.run_date)].copy()

    if "isCancel" in df.columns:
        df = df[~df["isCancel"].fillna(False)].copy()

    df["warehouseName"] = df["warehouseName"].map(normalize_warehouse)
    df["subject"] = df["subject"].map(normalize_text)
    df["regionName"] = df["regionName"].map(normalize_text)
    df["oblastOkrugName"] = df["oblastOkrugName"].map(normalize_text)
    df["supplierArticle"] = df["supplierArticle"].map(normalize_text)
    df["nmId"] = df["nmId"].map(normalize_nmid)
    df["finishedPrice"] = pd.to_numeric(df["finishedPrice"], errors="coerce")
    df["qty"] = 1

    before = len(df)
    df = df[~df["subject"].isin(cfg.excluded_subjects)].copy()
    log(f"Исключено строк заказов по запрещённым категориям: {before - len(df)}")
    return df


def load_stocks(storage: S3Storage, cfg: AppConfig) -> pd.DataFrame:
    df = load_weekly_window(storage, cfg.stocks_prefix_tpl.format(store=cfg.store_name), cfg.run_date, cfg.lookback_days, expected_sheet="Остатки")
    required = ["Склад", "Артикул WB", "Полное количество"]
    missing = [c for c in required if c not in df.columns]
    if missing:
        raise KeyError(f"В остатках отсутствуют обязательные колонки: {missing}")

    df = df.copy()
    date_col = "Дата запроса" if "Дата запроса" in df.columns else "Дата сбора"
    df["stock_date"] = pd.to_datetime(df[date_col], errors="coerce").dt.normalize()
    df = df[(df["stock_date"] >= (cfg.run_date - timedelta(days=cfg.lookback_days - 1))) & (df["stock_date"] <= cfg.run_date)].copy()

    df["warehouse"] = df["Склад"].map(normalize_warehouse)
    df["nmId"] = df["Артикул WB"].map(normalize_nmid)
    df["qty_full"] = pd.to_numeric(df["Полное количество"], errors="coerce").fillna(0)
    df["qty_available"] = pd.to_numeric(df["Доступно для продажи"], errors="coerce").fillna(0) if "Доступно для продажи" in df.columns else df["qty_full"]
    df["subject"] = df["Предмет"].map(normalize_text) if "Предмет" in df.columns else ""

    before = len(df)
    df = df[~df["subject"].isin(cfg.excluded_subjects)].copy()
    log(f"Исключено строк остатков по запрещённым категориям: {before - len(df)}")
    return df


def load_article_map_1c(storage: S3Storage, cfg: AppConfig) -> Dict[str, str]:
    df = storage.read_excel(cfg.article_map_1c_key)
    if isinstance(df, dict):
        df = next(iter(df.values()))

    wb_col = df.columns[0]
    col_1c = df.columns[2] if len(df.columns) >= 3 else df.columns[-1]

    out: Dict[str, str] = {}
    for _, row in df.iterrows():
        wb_article = normalize_nmid(row.get(wb_col))
        article_1c = normalize_text(row.get(col_1c))
        if wb_article:
            out[wb_article] = article_1c

    log(f"Загружено соответствий WB -> 1С: {len(out)}")
    return out


def load_1c_stocks(storage: S3Storage, cfg: AppConfig) -> pd.DataFrame:
    df = storage.read_excel(cfg.stocks_1c_key)
    if isinstance(df, dict):
        df = next(iter(df.values()))
    df = df.copy()
    df.columns = [normalize_text(c) for c in df.columns]
    return df


def prepare_daily_orders(orders: pd.DataFrame) -> pd.DataFrame:
    df = orders.copy()
    df["region_group"] = df["regionName"].map(REGION_TO_GROUP)

    # Для СЗФО не опираемся на название склада или точную область доставки:
    # WB может менять складские названия, но округ в заказах остаётся стабильным.
    # Все продажи СЗФО в базовом и эконом-режиме направляем на Склад Шушары.
    northwest_mask = df["oblastOkrugName"].eq(NORTHWEST_OKRUG_NAME)
    northwest_rows = int(northwest_mask.sum())
    if northwest_rows:
        df.loc[northwest_mask, "region_group"] = NORTHWEST_TARGET_WAREHOUSE
        log(f"Продажи СЗФО направлены на {NORTHWEST_TARGET_WAREHOUSE}: {northwest_rows:,} строк заказов")

    unmapped = int(df["region_group"].isna().sum())
    if unmapped:
        log(f"⚠️ Регионов без привязки к группе обслуживания: {unmapped}. Они будут отброшены.")
        df = df[df["region_group"].notna()].copy()

    return (
        df.groupby(["nmId", "supplierArticle", "subject", "date", "region_group", "oblastOkrugName"], as_index=False)
        .agg(qty=("qty", "sum"), avg_price=("finishedPrice", "mean"))
    )


def build_daily_grid(daily_orders: pd.DataFrame, cfg: AppConfig) -> pd.DataFrame:
    all_dates = pd.date_range(cfg.run_date - timedelta(days=cfg.lookback_days - 1), cfg.run_date, freq="D")
    keys = daily_orders[["nmId", "supplierArticle", "subject", "region_group", "oblastOkrugName"]].drop_duplicates()
    keys["__tmp"] = 1
    dates_df = pd.DataFrame({"date": all_dates, "__tmp": 1})

    grid = keys.merge(dates_df, on="__tmp", how="outer").drop(columns="__tmp")
    grid = grid.merge(
        daily_orders,
        on=["nmId", "supplierArticle", "subject", "region_group", "oblastOkrugName", "date"],
        how="left",
    )
    grid["qty"] = grid["qty"].fillna(0)
    return grid


def prepare_stock_presence(stocks: pd.DataFrame):
    per_wh = (
        stocks.groupby(["stock_date", "nmId", "warehouse"], as_index=False)
        .agg(qty_full=("qty_full", "sum"), qty_available=("qty_available", "sum"))
    )

    history_dates = set(pd.to_datetime(per_wh["stock_date"]).dt.normalize().unique()) if not per_wh.empty else set()

    per_wh["district"] = per_wh["warehouse"].map(WAREHOUSE_TO_DISTRICT)
    per_district = (
        per_wh.groupby(["stock_date", "nmId", "district"], as_index=False)
        .agg(qty_full=("qty_full", "sum"), qty_available=("qty_available", "sum"))
    )

    latest_stock_date = per_wh["stock_date"].max() if not per_wh.empty else pd.NaT
    current_wh = per_wh[per_wh["stock_date"] == latest_stock_date].copy() if pd.notna(latest_stock_date) else per_wh.iloc[0:0].copy()
    current_wh = current_wh.rename(columns={"stock_date": "latest_stock_date"})

    return current_wh, history_dates, per_wh, per_district, latest_stock_date


def attach_presence_flags(grid: pd.DataFrame, per_wh: pd.DataFrame, per_district: pd.DataFrame, history_dates: Set[pd.Timestamp]) -> pd.DataFrame:
    grid = grid.copy()
    wh_presence = per_wh.copy()
    wh_presence["is_positive"] = wh_presence["qty_full"] > 0

    local_records: List[pd.DataFrame] = []
    for group in grid["region_group"].dropna().unique():
        needed = MOSCOW_CLUSTER if group == "MOSCOW_CLUSTER" else [group]
        tmp = (
            wh_presence[wh_presence["warehouse"].isin(needed)]
            .groupby(["stock_date", "nmId"], as_index=False)["is_positive"]
            .max()
        )
        tmp["region_group"] = group
        local_records.append(tmp)

    local_presence = pd.concat(local_records, ignore_index=True) if local_records else pd.DataFrame(columns=["stock_date", "nmId", "is_positive", "region_group"])
    local_presence = local_presence.rename(columns={"stock_date": "date", "is_positive": "local_positive"})
    grid = grid.merge(local_presence, on=["date", "nmId", "region_group"], how="left")

    district_presence = per_district.copy()
    district_presence["district_positive"] = district_presence["qty_full"] > 0
    district_presence = district_presence.rename(columns={"stock_date": "date"})

    def region_target_district(region_group: str) -> str:
        if region_group == "MOSCOW_CLUSTER":
            return "Центральный федеральный округ"
        if region_group == NORTHWEST_TARGET_WAREHOUSE:
            return NORTHWEST_OKRUG_NAME
        return WAREHOUSE_TO_DISTRICT.get(region_group, "")

    grid["target_district"] = grid["region_group"].map(region_target_district)

    grid = grid.merge(
        district_presence[["date", "nmId", "district", "district_positive"]],
        left_on=["date", "nmId", "target_district"],
        right_on=["date", "nmId", "district"],
        how="left",
    ).drop(columns=["district"])

    known_dates = set(pd.to_datetime(pd.Series(list(history_dates))).dt.normalize()) if history_dates else set()
    grid["history_date_exists"] = grid["date"].isin(known_dates)

    grid["local_positive"] = grid["local_positive"].astype("boolean")
    grid["district_positive"] = grid["district_positive"].astype("boolean")

    grid["local_positive"] = np.where(grid["history_date_exists"], grid["local_positive"].fillna(False), True)
    grid["district_positive"] = np.where(grid["history_date_exists"], grid["district_positive"].fillna(False), True)

    grid["status"] = np.select(
        [
            grid["local_positive"] == True,
            (grid["local_positive"] == False) & (grid["district_positive"] == True),
            (grid["local_positive"] == False) & (grid["district_positive"] == False),
        ],
        ["local", "okrug", "far"],
        default="local",
    )

    return grid


def mark_valid_days(group_df: pd.DataFrame, cfg: AppConfig) -> pd.DataFrame:
    df = group_df.copy()
    base_price = df.loc[df["qty"] > 0, "avg_price"].mean()

    df["promo_invalid"] = False
    if pd.notna(base_price):
        df.loc[df["qty"] > 0, "promo_invalid"] = (
            df.loc[df["qty"] > 0, "avg_price"] < (1 - cfg.price_drop_threshold) * base_price
        )

    prelim_mean = df.loc[~df["promo_invalid"], "qty"].mean()
    prelim_mean = 0.0 if pd.isna(prelim_mean) else float(prelim_mean)
    sales_floor = prelim_mean * (1 - cfg.sales_drop_threshold)

    df["drop_invalid"] = (df["qty"] > 0) & (~df["promo_invalid"]) & (df["qty"] < sales_floor)
    df["valid_day"] = ~(df["promo_invalid"] | df["drop_invalid"])
    return df


def aggregate_region_metrics(grid: pd.DataFrame, cfg: AppConfig) -> pd.DataFrame:
    rows: List[Dict[str, object]] = []
    group_cols = ["nmId", "supplierArticle", "subject", "region_group", "oblastOkrugName"]

    for keys, part in grid.groupby(group_cols, dropna=False):
        part = mark_valid_days(part.sort_values("date"), cfg)

        base90 = part.loc[part["valid_day"], "qty"].mean()
        if pd.isna(base90):
            base90 = part["qty"].mean()
        base90 = 0.0 if pd.isna(base90) else float(base90)

        last14 = part[part["date"] >= (cfg.run_date - timedelta(days=cfg.recent_days - 1))]
        base14 = last14.loc[last14["valid_day"], "qty"].mean()
        if pd.isna(base14):
            base14 = last14["qty"].mean()
        base14 = 0.0 if pd.isna(base14) else float(base14)

        d_local90 = int((part["status"] == "local").sum())
        d_okrug90 = int((part["status"] == "okrug").sum())
        d_far90 = int((part["status"] == "far").sum())

        d_local14 = int((last14["status"] == "local").sum())
        d_okrug14 = int((last14["status"] == "okrug").sum())
        d_far14 = int((last14["status"] == "far").sum())

        avg_adj90 = base90 * (cfg.coeff_local * d_local90 + cfg.coeff_okrug * d_okrug90 + cfg.coeff_far * d_far90) / max(cfg.lookback_days, 1)
        avg_adj14 = base14 * (cfg.coeff_local * d_local14 + cfg.coeff_okrug * d_okrug14 + cfg.coeff_far * d_far14) / max(cfg.recent_days, 1)

        price90 = part.loc[part["qty"] > 0, "avg_price"].mean()
        price14 = last14.loc[last14["qty"] > 0, "avg_price"].mean()

        rows.append(
            {
                "nmId": keys[0],
                "supplierArticle": keys[1],
                "subject": keys[2],
                "region_group": keys[3],
                "oblastOkrugName": keys[4],
                "sales_90": int(part["qty"].sum()),
                "sales_14": int(last14["qty"].sum()),
                "avg_adj90_region": float(avg_adj90),
                "avg_adj14_region": float(avg_adj14),
                "avg_price90_region": float(price90) if pd.notna(price90) else np.nan,
                "avg_price14_region": float(price14) if pd.notna(price14) else np.nan,
            }
        )

    return pd.DataFrame(rows)


def choose_final_daily_demand(region_metrics: pd.DataFrame, cfg: AppConfig) -> pd.DataFrame:
    rows: List[Dict[str, object]] = []

    for (nmid, supplier_article, subject), part in region_metrics.groupby(["nmId", "supplierArticle", "subject"], dropna=False):
        avg90 = float(part["avg_adj90_region"].sum())
        avg14 = float(part["avg_adj14_region"].sum())
        sales90 = int(part["sales_90"].sum())
        sales14 = int(part["sales_14"].sum())

        w90 = np.maximum(part["sales_90"].to_numpy(dtype=float), 1)
        w14 = np.maximum(part["sales_14"].to_numpy(dtype=float), 1)
        p90 = part["avg_price90_region"].fillna(0).to_numpy(dtype=float)
        p14 = part["avg_price14_region"].fillna(0).to_numpy(dtype=float)

        price90 = float(np.average(p90, weights=w90)) if len(part) else np.nan
        price14 = float(np.average(p14, weights=w14)) if len(part) else np.nan

        can_use_14 = avg14 > avg90 * cfg.growth_threshold and (
            pd.isna(price90) or pd.isna(price14) or price14 >= (1 - cfg.price_drop_threshold) * price90
        )

        base_daily = avg14 if can_use_14 else avg90

        rows.append(
            {
                "nmId": nmid,
                "supplierArticle": supplier_article,
                "subject": subject,
                "sales_90_total": sales90,
                "sales_14_total": sales14,
                "daily_demand_final": float(base_daily * cfg.season_coeff),
            }
        )

    return pd.DataFrame(rows)


def build_warehouse_shares(region_metrics: pd.DataFrame) -> pd.DataFrame:
    rows: List[Dict[str, object]] = []

    for (nmid, supplier_article, subject), part in region_metrics.groupby(["nmId", "supplierArticle", "subject"], dropna=False):
        total_sales = float(part["sales_90"].sum())
        warehouse_sales: Dict[str, float] = defaultdict(float)

        for _, row in part.iterrows():
            group = row["region_group"]
            sales = float(row["sales_90"])

            if group == "MOSCOW_CLUSTER":
                for warehouse, share in MOSCOW_SPLIT_TARGET.items():
                    warehouse_sales[warehouse] += sales * share
            else:
                warehouse_sales[group] += sales

        if total_sales <= 0 and warehouse_sales:
            for warehouse in warehouse_sales:
                warehouse_sales[warehouse] = 1.0
            total_sales = sum(warehouse_sales.values())

        for warehouse, sales in warehouse_sales.items():
            rows.append(
                {
                    "nmId": nmid,
                    "supplierArticle": supplier_article,
                    "subject": subject,
                    "warehouse": warehouse,
                    "warehouse_share": (sales / total_sales) if total_sales > 0 else 0.0,
                }
            )

    shares = pd.DataFrame(rows)
    if not shares.empty:
        sums = shares.groupby("nmId")["warehouse_share"].transform("sum").replace(0, 1)
        shares["warehouse_share"] = shares["warehouse_share"] / sums

    return shares


def apply_strategy(shares_df: pd.DataFrame, cfg: AppConfig) -> pd.DataFrame:
    df = shares_df.copy()
    if not df.empty and "warehouse" in df.columns:
        df["warehouse"] = df["warehouse"].map(normalize_warehouse)

    if cfg.strategy_mode != "economy":
        return df

    # Эконом-режим заменяет только заданные склады. СЗФО всегда остаётся на Шушарах.
    mask = (
        df["subject"].isin(cfg.economy_subjects)
        & df["warehouse"].isin(ECONOMY_REPLACEMENT_MAP)
        & df["warehouse"].ne(NORTHWEST_TARGET_WAREHOUSE)
    )
    df.loc[mask, "warehouse"] = df.loc[mask, "warehouse"].map(ECONOMY_REPLACEMENT_MAP)

    df = (
        df.groupby(["nmId", "supplierArticle", "subject", "warehouse"], as_index=False)
        .agg(warehouse_share=("warehouse_share", "sum"))
    )

    sums = df.groupby("nmId")["warehouse_share"].transform("sum").replace(0, 1)
    df["warehouse_share"] = df["warehouse_share"] / sums
    return df


def current_stock_by_warehouse(current_wh: pd.DataFrame) -> pd.DataFrame:
    return (
        current_wh.groupby(["nmId", "warehouse"], as_index=False)
        .agg(
            current_stock_full=("qty_full", "sum"),
            current_stock_available=("qty_available", "sum"),
        )
    )


def allocate_low_turnover(shares_sku: pd.DataFrame, cfg: AppConfig) -> Dict[str, int]:
    weights = {row["warehouse"]: float(row["warehouse_share"]) for _, row in shares_sku.iterrows() if row["warehouse"]}

    selected = dict(weights)
    for _, warehouse in cfg.district_primary_warehouse.items():
        selected.setdefault(warehouse, 0.0001)

    selected = {warehouse: weight for warehouse, weight in selected.items() if warehouse in ALL_TARGET_WAREHOUSES}
    if not selected:
        selected = {warehouse: 1.0 for warehouse in cfg.district_primary_warehouse.values()}

    return largest_remainder_allocation(cfg.low_turnover_network_stock, selected, minimum_one_for_nonzero=True)


def calculate_supply_plan(
    sku_df: pd.DataFrame,
    shares_df: pd.DataFrame,
    current_stock_df: pd.DataFrame,
    article_1c_map: Dict[str, str],
    cfg: AppConfig,
) -> pd.DataFrame:
    current_lookup = (
        current_stock_df.set_index(["nmId", "warehouse"]).to_dict("index")
        if not current_stock_df.empty
        else {}
    )

    network_stock_map = (
        current_stock_df.groupby("nmId", as_index=False)
        .agg(
            network_stock_full=("current_stock_full", "sum"),
            network_stock_available=("current_stock_available", "sum"),
        )
        .set_index("nmId")
        .to_dict("index")
        if not current_stock_df.empty
        else {}
    )

    rows: List[Dict[str, object]] = []

    for _, sku in sku_df.iterrows():
        nmid = sku["nmId"]
        sku_shares = shares_df[shares_df["nmId"] == nmid].copy()
        if sku_shares.empty:
            continue

        supplier_article = normalize_text(sku["supplierArticle"])
        article_1c = resolve_article_1c_for_store(nmid, supplier_article, article_1c_map, cfg)
        network_available = float(network_stock_map.get(nmid, {}).get("network_stock_available", 0.0))

        if int(sku["sales_90_total"]) < cfg.low_turnover_sales_threshold:
            target_network_stock = float(cfg.low_turnover_network_stock)
            net_need = max(0.0, target_network_stock - network_available)

            if net_need <= 0:
                continue

            allocations = allocate_low_turnover(sku_shares, cfg)
            total_alloc = sum(allocations.values())
            if total_alloc <= 0:
                continue

            for warehouse, alloc_value in allocations.items():
                share_weight = alloc_value / total_alloc
                warehouse_need = int(math.ceil(net_need * share_weight))

                wh_row = current_lookup.get((nmid, warehouse), {})
                current_full = float(wh_row.get("current_stock_full", 0))
                current_available = float(wh_row.get("current_stock_available", 0))

                if warehouse_need <= 0:
                    continue

                rows.append(
                    {
                        "nmId": nmid,
                        "supplierArticle": supplier_article,
                        "subject": sku["subject"],
                        "Артикул 1С": article_1c,
                        "warehouse": warehouse,
                        "warehouse_share": float(
                            sku_shares.loc[sku_shares["warehouse"] == warehouse, "warehouse_share"].sum()
                        ) if warehouse in sku_shares["warehouse"].values else 0.0,
                        "daily_demand_final": float(sku["daily_demand_final"]),
                        "target_stock": target_network_stock,
                        "network_stock_available": network_available,
                        "current_stock_full": current_full,
                        "current_stock_available": current_available,
                        "to_supply": float(warehouse_need),
                        "calc_mode": "low_turnover",
                    }
                )
            continue

        sku_shares = sku_shares.copy()
        sku_shares["target_stock_wh"] = (
            float(sku["daily_demand_final"]) * sku_shares["warehouse_share"].astype(float) * cfg.target_days
        )

        network_target = float(sku_shares["target_stock_wh"].sum())
        net_need = max(0.0, network_target - network_available)

        if net_need <= 0:
            continue

        total_target = float(sku_shares["target_stock_wh"].sum())
        if total_target <= 0:
            continue

        for _, share_row in sku_shares.iterrows():
            warehouse = share_row["warehouse"]
            warehouse_target = float(share_row["target_stock_wh"])
            warehouse_share = warehouse_target / total_target if total_target > 0 else 0.0
            warehouse_need = int(math.ceil(net_need * warehouse_share))

            wh_row = current_lookup.get((nmid, warehouse), {})
            current_full = float(wh_row.get("current_stock_full", 0))
            current_available = float(wh_row.get("current_stock_available", 0))

            if warehouse_need <= 0:
                continue

            rows.append(
                {
                    "nmId": nmid,
                    "supplierArticle": supplier_article,
                    "subject": sku["subject"],
                    "Артикул 1С": article_1c,
                    "warehouse": warehouse,
                    "warehouse_share": float(share_row["warehouse_share"]),
                    "daily_demand_final": float(sku["daily_demand_final"]),
                    "target_stock": warehouse_target,
                    "network_stock_available": network_available,
                    "current_stock_full": current_full,
                    "current_stock_available": current_available,
                    "to_supply": float(warehouse_need),
                    "calc_mode": "regular",
                }
            )

    plan = pd.DataFrame(rows)
    if plan.empty:
        return plan

    plan = (
        plan.groupby(
            ["nmId", "supplierArticle", "subject", "Артикул 1С", "warehouse", "calc_mode"],
            as_index=False,
        )
        .agg(
            warehouse_share=("warehouse_share", "sum"),
            daily_demand_final=("daily_demand_final", "first"),
            target_stock=("target_stock", "sum"),
            network_stock_available=("network_stock_available", "first"),
            current_stock_full=("current_stock_full", "sum"),
            current_stock_available=("current_stock_available", "sum"),
            to_supply=("to_supply", "sum"),
        )
    )

    plan = plan[plan["to_supply"] > 0].copy()
    return plan



def resolve_1c_column_name(df: pd.DataFrame, candidates: Sequence[str]) -> Optional[str]:
    raw_columns = [normalize_text(col) for col in df.columns]
    lower_map = {col.casefold(): col for col in raw_columns if col}
    compact_map = {re.sub(r"\s+", " ", col).replace(" - ", "-").casefold(): col for col in raw_columns if col}

    for candidate in candidates:
        candidate_norm = normalize_text(candidate)
        if not candidate_norm:
            continue
        direct = lower_map.get(candidate_norm.casefold())
        if direct:
            return direct
        compact = compact_map.get(re.sub(r"\s+", " ", candidate_norm).replace(" - ", "-").casefold())
        if compact:
            return compact
    return None


def build_network_stock_summary(current_stock_df: pd.DataFrame) -> Dict[str, Dict[str, float]]:
    if current_stock_df.empty:
        return {}
    summary = (
        current_stock_df.groupby("nmId", as_index=False)
        .agg(
            network_stock_full=("current_stock_full", "sum"),
            network_stock_available=("current_stock_available", "sum"),
        )
    )
    summary["nmId"] = summary["nmId"].map(normalize_nmid)
    return summary.set_index("nmId").to_dict("index")


def build_local_stock_map(df_1c_stocks: pd.DataFrame) -> Dict[str, float]:
    if df_1c_stocks.empty or "Артикул" not in df_1c_stocks.columns:
        return {}

    df = df_1c_stocks.copy()
    df.columns = [normalize_text(col) for col in df.columns]
    df["Артикул"] = df["Артикул"].map(normalize_text)

    component_totals: List[str] = []
    weighted_cols: List[str] = []

    for aliases, weight, label in ONE_C_LOCAL_STOCK_COMPONENTS:
        resolved_col = resolve_1c_column_name(df, aliases)
        tmp_col = f"__local_component__{label}"
        if resolved_col is None:
            df[tmp_col] = 0.0
            component_totals.append(f"{label}=0 (колонка не найдена)")
        else:
            source_values = pd.to_numeric(df[resolved_col], errors="coerce").fillna(0.0)
            weighted_values = source_values * float(weight)
            df[tmp_col] = weighted_values
            component_totals.append(
                f"{label}={round(source_values.sum()):,} × {weight:g} = {round(weighted_values.sum()):,}"
            )
        weighted_cols.append(tmp_col)

    df["local_stock_total"] = df[weighted_cols].sum(axis=1)
    total_local = round(float(df["local_stock_total"].sum()))
    log("Остатки Липецк считаем как: " + " + ".join(component_totals) + f". Итого={total_local:,}")

    return (
        df.groupby("Артикул", as_index=False)["local_stock_total"]
        .sum()
        .set_index("Артикул")["local_stock_total"]
        .to_dict()
    )


def load_transit_stock_map(storage: S3Storage, cfg: AppConfig, arrival_date: datetime) -> Dict[str, float]:
    keys = storage.list_keys(cfg.one_c_aux_prefix)
    transit_keys = [k for k in keys if re.search(r"/В пути \d{2}-\d{2}-(?:\d{2}|\d{4})\.xlsx$", k)]
    if not transit_keys:
        log("⚠️ Не найдены файлы 'В пути ...xlsx' для расчёта транзита")
        return {}

    transit_map: Dict[str, float] = defaultdict(float)
    included_files: List[Tuple[str, datetime, datetime]] = []
    for key in transit_keys:
        file_date = parse_ddmmyy_date(Path(key).name)
        if file_date is None:
            log(f"⚠️ Не удалось распознать дату в файле транзита: {key}")
            continue
        available_date = file_date + timedelta(days=14)
        if available_date > arrival_date:
            continue

        try:
            df = read_transit_sheet(storage, key)
        except Exception as exc:
            log(f"⚠️ Не удалось прочитать файл в пути {key}: {exc}")
            continue

        if df is None or df.empty:
            continue

        code_col = first_present_column(df, ["codes", "артикул 1с", "артикул", "code"])
        if code_col is None:
            code_col = df.columns[0]

        qty_col = first_present_column(df, ["заказ мп", "распределение мп", "количество", "qty", "шт"])
        if qty_col is None:
            qty_col = first_present_column(df, ["order | pcs", "order pcs", "order"])
        if qty_col is None:
            log(f"⚠️ В файле {key} не найдена колонка количества для транзита. Колонки: {list(df.columns)}")
            continue

        file_qty_total = 0.0
        for _, row in df.iterrows():
            article_1c = normalize_text(row.get(code_col))
            qty = pd.to_numeric(row.get(qty_col), errors="coerce")
            if article_1c and pd.notna(qty):
                qty_value = float(qty)
                transit_map[article_1c] += qty_value
                file_qty_total += qty_value

        included_files.append((Path(key).name, file_date, available_date))
        log(
            f"Транзит учтён из {Path(key).name}: колонка '{qty_col}', строк SKU={len(df)}, сумма={round(file_qty_total):,}, доступно с {available_date:%Y-%m-%d}"
        )

    if not transit_map:
        log("⚠️ После чтения файлов транзита карта 'Товары в пути' пустая")
    else:
        log(f"Итого товаров в пути до приезда: {round(sum(transit_map.values())):,} шт. по {len(transit_map):,} артикулам 1С")

    return dict(transit_map)


def load_abc_month_metrics(storage: S3Storage, cfg: AppConfig) -> pd.DataFrame:
    target = normalize_text(cfg.abc_target_month)
    if not re.fullmatch(r"\d{4}-\d{2}", target):
        raise ValueError(f"Неверный формат WB_ABC_TARGET_MONTH: {cfg.abc_target_month}. Ожидается YYYY-MM")
    year, month = map(int, target.split("-"))
    month_start = datetime(year, month, 1)
    month_end = datetime(year, month, calendar.monthrange(year, month)[1])

    keys = [k for k in storage.list_keys(cfg.abc_prefix) if "wb_abc_report_goods__" in Path(k).name]
    if not keys:
        return pd.DataFrame(columns=["nmId", "supplierArticle_norm", "sales_month_qty", "gross_profit_month"])

    exact_prefix = f"wb_abc_report_goods__{month_start:%d.%m.%Y}-{month_end:%d.%m.%Y}__"
    exact = sorted([k for k in keys if exact_prefix in Path(k).name])
    selected_keys = exact[-1:] if exact else []

    if not selected_keys:
        overlaps = []
        for key in keys:
            start_dt, end_dt = parse_ddmmyyyy_range_from_key(Path(key).name)
            if start_dt is None or end_dt is None:
                continue
            if start_dt <= month_end and end_dt >= month_start:
                overlaps.append((start_dt, end_dt, key))
        selected_keys = [x[2] for x in sorted(overlaps, key=lambda x: (x[0], x[1], x[2]))]

    if not selected_keys:
        return pd.DataFrame(columns=["nmId", "supplierArticle_norm", "sales_month_qty", "gross_profit_month"])

    parts: List[pd.DataFrame] = []
    for key in selected_keys:
        try:
            df = storage.read_excel(key)
            if isinstance(df, dict):
                df = next(iter(df.values()))
        except Exception as exc:
            log(f"⚠️ Не удалось прочитать ABC-файл {key}: {exc}")
            continue
        if df is None or df.empty:
            continue

        nm_col = first_present_column(df, ["артикул wb"])
        supplier_col = first_present_column(df, ["артикул продавца"])
        sales_col = first_present_column(df, ["кол-во продаж"])
        gp_col = first_present_column(df, ["валовая прибыль"])
        if nm_col is None or supplier_col is None or sales_col is None or gp_col is None:
            log(f"⚠️ В ABC-файле {key} не найдены нужные колонки")
            continue

        tmp = df[[nm_col, supplier_col, sales_col, gp_col]].copy()
        tmp.columns = ["nmId", "supplierArticle", "sales_month_qty", "gross_profit_month"]
        tmp["nmId"] = tmp["nmId"].map(normalize_nmid)
        tmp["supplierArticle_norm"] = tmp["supplierArticle"].map(normalize_supplier_article_key)
        tmp["sales_month_qty"] = pd.to_numeric(tmp["sales_month_qty"], errors="coerce").fillna(0)
        tmp["gross_profit_month"] = pd.to_numeric(tmp["gross_profit_month"], errors="coerce").fillna(0)
        parts.append(tmp[["nmId", "supplierArticle_norm", "sales_month_qty", "gross_profit_month"]])

    if not parts:
        return pd.DataFrame(columns=["nmId", "supplierArticle_norm", "sales_month_qty", "gross_profit_month"])

    result = pd.concat(parts, ignore_index=True)
    return (
        result.groupby(["nmId", "supplierArticle_norm"], as_index=False)
        .agg(
            sales_month_qty=("sales_month_qty", "sum"),
            gross_profit_month=("gross_profit_month", "sum"),
        )
    )


def build_supplier_sku_metrics(region_metrics: pd.DataFrame, cfg: AppConfig) -> pd.DataFrame:
    rows: List[Dict[str, object]] = []

    for (nmid, supplier_article, subject), part in region_metrics.groupby(["nmId", "supplierArticle", "subject"], dropna=False):
        avg90 = float(part["avg_adj90_region"].sum())
        avg14 = float(part["avg_adj14_region"].sum())
        sales90 = int(part["sales_90"].sum())
        sales14 = int(part["sales_14"].sum())

        w90 = np.maximum(part["sales_90"].to_numpy(dtype=float), 1)
        w14 = np.maximum(part["sales_14"].to_numpy(dtype=float), 1)
        p90 = part["avg_price90_region"].fillna(0).to_numpy(dtype=float)
        p14 = part["avg_price14_region"].fillna(0).to_numpy(dtype=float)

        price90 = float(np.average(p90, weights=w90)) if len(part) else np.nan
        price14 = float(np.average(p14, weights=w14)) if len(part) else np.nan

        can_use_14 = avg14 > avg90 * cfg.growth_threshold and (
            pd.isna(price90) or pd.isna(price14) or price14 >= (1 - cfg.price_drop_threshold) * price90
        )
        breakthrough = avg14 > avg90 * cfg.supplier_breakthrough_threshold and (
            pd.isna(price90) or pd.isna(price14) or price14 >= (1 - cfg.price_drop_threshold) * price90
        )

        base_daily = avg14 if can_use_14 else avg90
        supplier_daily = avg14 if breakthrough else base_daily

        rows.append(
            {
                "nmId": normalize_nmid(nmid),
                "supplierArticle": supplier_article,
                "supplierArticle_norm": normalize_supplier_article_key(supplier_article),
                "subject": subject,
                "sales_90_total": sales90,
                "sales_14_total": sales14,
                "daily_base_avg90": float(avg90),
                "daily_base_avg14": float(avg14),
                "daily_demand_base": float(base_daily),
                "daily_demand_supplier": float(supplier_daily),
                "use_recent_14d": bool(can_use_14),
                "is_breakthrough": bool(breakthrough),
            }
        )

    return pd.DataFrame(rows)


def get_plan_month_coeff(category: str, supplier_article: str, month_iso: str, default_coeff: float) -> Tuple[float, str]:
    article_key = normalize_supplier_article_key(supplier_article)
    category_key = normalize_text(category)
    coeff = PLAN_SKU_MONTH_COEFFS.get(category_key, {}).get(article_key, {}).get(month_iso)
    if coeff is not None:
        return float(coeff), "plan"
    return float(default_coeff), "manual"


def forecast_monthly_chained_demand(
    base_daily: float,
    category: str,
    supplier_article: str,
    start_date: datetime,
    days: int,
    default_coeff: float,
) -> Tuple[float, List[Dict[str, object]]]:
    if days <= 0 or base_daily <= 0:
        return 0.0, []

    remaining = int(days)
    cursor = start_date
    current_daily = float(base_daily)
    total = 0.0
    parts: List[Dict[str, object]] = []

    while remaining > 0:
        segment_end = min(end_of_month(cursor), cursor + timedelta(days=remaining - 1))
        segment_days = (segment_end - cursor).days + 1
        coeff, coeff_source = get_plan_month_coeff(category, supplier_article, month_key(cursor), default_coeff)
        current_daily = current_daily * coeff
        segment_units = current_daily * segment_days
        total += segment_units
        parts.append(
            {
                "month": month_key(cursor),
                "days": int(segment_days),
                "coeff": float(coeff),
                "coeff_source": coeff_source,
                "daily_after_coeff": float(current_daily),
                "units": float(segment_units),
            }
        )
        cursor = segment_end + timedelta(days=1)
        remaining -= segment_days

    return total, parts


def stringify_forecast_parts(parts: Sequence[Dict[str, object]]) -> str:
    formatted: List[str] = []
    for part in parts:
        formatted.append(
            f"{part['month']}: {part['daily_after_coeff']:.2f} × {part['days']} дн × коэф {part['coeff']:.4f} ({part['coeff_source']}) = {part['units']:.2f}"
        )
    return " | ".join(formatted)


def build_supplier_order_report(
    storage: S3Storage,
    cfg: AppConfig,
    region_metrics: pd.DataFrame,
    current_stock_df: pd.DataFrame,
    article_1c_map: Dict[str, str],
    stocks_1c_raw: pd.DataFrame,
) -> Tuple[pd.DataFrame, pd.DataFrame]:
    supplier_metrics = build_supplier_sku_metrics(region_metrics, cfg)
    if supplier_metrics.empty:
        return pd.DataFrame(), pd.DataFrame()

    arrival_date = cfg.run_date + timedelta(days=cfg.supplier_lead_days)
    forecast_start = arrival_date + timedelta(days=1)

    network_stock_map = build_network_stock_summary(current_stock_df)
    local_stock_map = build_local_stock_map(stocks_1c_raw)
    transit_stock_map = load_transit_stock_map(storage, cfg, arrival_date)
    abc_month = load_abc_month_metrics(storage, cfg)

    abc_by_nmid = abc_month.groupby("nmId", as_index=False).agg(
        sales_month_qty=("sales_month_qty", "sum"),
        gross_profit_month=("gross_profit_month", "sum"),
    ) if not abc_month.empty else pd.DataFrame(columns=["nmId", "sales_month_qty", "gross_profit_month"])
    abc_by_article = abc_month.groupby("supplierArticle_norm", as_index=False).agg(
        sales_month_qty=("sales_month_qty", "sum"),
        gross_profit_month=("gross_profit_month", "sum"),
    ) if not abc_month.empty else pd.DataFrame(columns=["supplierArticle_norm", "sales_month_qty", "gross_profit_month"])

    abc_nmid_map = abc_by_nmid.set_index("nmId").to_dict("index") if not abc_by_nmid.empty else {}
    abc_article_map = abc_by_article.set_index("supplierArticle_norm").to_dict("index") if not abc_by_article.empty else {}

    rows: List[Dict[str, object]] = []
    trace_rows: List[Dict[str, object]] = []

    for _, sku in supplier_metrics.iterrows():
        nmid = normalize_nmid(sku["nmId"])
        supplier_article = normalize_text(sku["supplierArticle"])
        supplier_article_norm = normalize_supplier_article_key(supplier_article)
        subject = normalize_text(sku["subject"])
        article_1c = article_1c_map.get(nmid, "")

        network_available = float(network_stock_map.get(nmid, {}).get("network_stock_available", 0.0))
        network_full = float(network_stock_map.get(nmid, {}).get("network_stock_full", 0.0))
        local_stock = float(local_stock_map.get(article_1c, 0.0))
        transit_stock = float(transit_stock_map.get(article_1c, 0.0))
        total_stock_now = network_available + local_stock + transit_stock

        daily_used = float(sku["daily_demand_supplier"])
        demand_before_arrival, lead_parts = forecast_monthly_chained_demand(
            base_daily=daily_used,
            category=subject,
            supplier_article=supplier_article_norm,
            start_date=cfg.run_date + timedelta(days=1),
            days=cfg.supplier_lead_days,
            default_coeff=cfg.supplier_default_coeff,
        )
        demand_after_arrival, post_parts = forecast_monthly_chained_demand(
            base_daily=daily_used,
            category=subject,
            supplier_article=supplier_article_norm,
            start_date=forecast_start,
            days=cfg.supplier_coverage_days,
            default_coeff=cfg.supplier_default_coeff,
        )

        stock_at_arrival_raw = total_stock_now - demand_before_arrival
        stockout_before_arrival = stock_at_arrival_raw < 0
        stock_at_arrival = max(0.0, stock_at_arrival_raw)

        post_arrival_target = float(demand_after_arrival)
        low_sales_90 = int(sku["sales_90_total"]) < cfg.low_turnover_sales_threshold
        if low_sales_90:
            post_arrival_target = max(post_arrival_target, float(cfg.low_turnover_network_stock))

        recommended_order = max(0.0, post_arrival_target - stock_at_arrival)

        is_delist = article_1c in DELIST_1C_ARTICLES or nmid in DELIST_WB_ARTICLES
        if is_delist:
            recommended_order = 0.0

        abc_row = abc_article_map.get(supplier_article_norm) or abc_nmid_map.get(nmid) or {}
        sales_month_qty = float(abc_row.get("sales_month_qty", 0.0))
        gross_profit_month = float(abc_row.get("gross_profit_month", 0.0))

        status_parts: List[str] = []
        if is_delist:
            status_parts.append("Delist")
        if bool(sku["is_breakthrough"]):
            status_parts.append("Прорыв")
        if low_sales_90:
            status_parts.append("Меньше 100 продаж за 90 дней")
        if stockout_before_arrival:
            status_parts.append("Не хватает до приезда")
        if not status_parts:
            status_parts.append("Стандарт")

        rows.append(
            {
                "Артикул WB": nmid,
                "Артикул продавца": supplier_article,
                "Артикул 1С": article_1c,
                "Предмет": subject,
                "Среднесуточные продажи 90д": round(float(sku["daily_base_avg90"]), 2),
                "Среднесуточные продажи 14д": round(float(sku["daily_base_avg14"]), 2),
                "Среднесуточные продажи расчетные": round(float(sku["daily_demand_base"]), 2),
                "Среднесуточные продажи итоговые": round(daily_used, 2),
                "Остаток WB доступный, шт": round(network_available),
                "Остаток WB полный, шт": round(network_full),
                "Остатки Липецк, шт": round(local_stock),
                "Товары в пути до приезда, шт": round(transit_stock),
                "Остатки всего сейчас, шт": round(total_stock_now),
                "Спрос до приезда, шт": round(demand_before_arrival),
                "Остаток на дату приезда, шт": round(stock_at_arrival),
                "Будет OOS до приезда": "Да" if stockout_before_arrival else "Нет",
                f"Прогноз после приезда на {cfg.supplier_coverage_days} дней, шт": round(demand_after_arrival),
                "Цель после приезда, шт": round(post_arrival_target),
                "Заказ в Турцию, шт": int(math.ceil(recommended_order)),
                "Статус": ", ".join(status_parts),
                "Delist": "Да" if is_delist else "Нет",
                "Прорыв": "Да" if bool(sku["is_breakthrough"]) else "Нет",
                "Меньше 100 продаж за 90 дней": "Да" if low_sales_90 else "Нет",
                f"Продажи {cfg.abc_target_month}, шт": round(sales_month_qty),
                f"Валовая прибыль {cfg.abc_target_month}, ₽": round(gross_profit_month, 2),
                "Источник коэффициентов": "plan" if subject in PLAN_SKU_MONTH_COEFFS and supplier_article_norm in PLAN_SKU_MONTH_COEFFS.get(subject, {}) else "manual",
                "Помесячный расчет до приезда": stringify_forecast_parts(lead_parts),
                "Помесячный расчет после приезда": stringify_forecast_parts(post_parts),
            }
        )

        for part in lead_parts:
            trace_rows.append(
                {
                    "Артикул WB": nmid,
                    "Артикул продавца": supplier_article,
                    "Артикул 1С": article_1c,
                    "Предмет": subject,
                    "Этап": "До приезда",
                    "Месяц": part["month"],
                    "Дней в сегменте": part["days"],
                    "Коэффициент": part["coeff"],
                    "Источник коэффициента": part["coeff_source"],
                    "Среднесуточные после коэффициента": round(part["daily_after_coeff"], 2),
                    "Прогноз, шт": round(part["units"], 4),
                }
            )
        for part in post_parts:
            trace_rows.append(
                {
                    "Артикул WB": nmid,
                    "Артикул продавца": supplier_article,
                    "Артикул 1С": article_1c,
                    "Предмет": subject,
                    "Этап": "После приезда",
                    "Месяц": part["month"],
                    "Дней в сегменте": part["days"],
                    "Коэффициент": part["coeff"],
                    "Источник коэффициента": part["coeff_source"],
                    "Среднесуточные после коэффициента": round(part["daily_after_coeff"], 2),
                    "Прогноз, шт": round(part["units"], 4),
                }
            )

    result = pd.DataFrame(rows)
    if result.empty:
        return result, pd.DataFrame(trace_rows)

    result = result.sort_values(["Delist", "Заказ в Турцию, шт", "Артикул продавца"], ascending=[True, False, True]).copy()
    return result, pd.DataFrame(trace_rows)


def style_workbook(path: str) -> None:
    wb = load_workbook(path)
    try:
        for ws in wb.worksheets:
            ws.freeze_panes = "A2"
            widths: Dict[int, int] = {}
            for row in ws.iter_rows():
                for cell in row:
                    value = "" if cell.value is None else str(cell.value)
                    if not value:
                        continue
                    widths[cell.column] = max(widths.get(cell.column, 0), min(len(value) + 2, 60))
            for col_idx, width in widths.items():
                ws.column_dimensions[get_column_letter(col_idx)].width = max(ws.column_dimensions[get_column_letter(col_idx)].width or 0, width)
        wb.save(path)
    finally:
        wb.close()


def style_supplier_workbook(path: str) -> None:
    wb = load_workbook(path)
    if "Заказ в Турцию" not in wb.sheetnames:
        wb.save(path)
        wb.close()
        return

    for sheet_name in ["Заказ в Турцию", "Помесячный расчет"]:
        if sheet_name not in wb.sheetnames:
            continue
        sheet = wb[sheet_name]
        for col_idx in range(1, sheet.max_column + 1):
            header_value = normalize_text(sheet.cell(1, col_idx).value)
            if "Среднесуточные" in header_value:
                for row_idx in range(2, sheet.max_row + 1):
                    sheet.cell(row_idx, col_idx).number_format = "0.00"

    ws = wb["Заказ в Турцию"]
    header_map = {normalize_text(ws.cell(1, col).value): col for col in range(1, ws.max_column + 1)}
    delist_col = header_map.get("Delist")
    low_col = header_map.get("Меньше 100 продаж за 90 дней")

    red_fill = PatternFill(fill_type="solid", fgColor="FF0000")
    orange_fill = PatternFill(fill_type="solid", fgColor="FFA500")

    for row_idx in range(2, ws.max_row + 1):
        delist_flag = ws.cell(row_idx, delist_col).value if delist_col else ""
        low_flag = ws.cell(row_idx, low_col).value if low_col else ""
        if str(delist_flag).strip() == "Да":
            for col_idx in range(1, ws.max_column + 1):
                ws.cell(row_idx, col_idx).fill = red_fill
        elif str(low_flag).strip() == "Да":
            for col_idx in range(1, ws.max_column + 1):
                ws.cell(row_idx, col_idx).fill = orange_fill

    wb.save(path)
    wb.close()


def run_supplier_mode(
    storage: S3Storage,
    cfg: AppConfig,
    article_1c_map: Dict[str, str],
    stocks_1c_raw: pd.DataFrame,
    current_stock_df: pd.DataFrame,
    region_metrics: pd.DataFrame,
    stocks_1c_local: str,
) -> str:
    supplier_df, trace_df = build_supplier_order_report(
        storage=storage,
        cfg=cfg,
        region_metrics=region_metrics,
        current_stock_df=current_stock_df,
        article_1c_map=article_1c_map,
        stocks_1c_raw=stocks_1c_raw,
    )
    if supplier_df.empty:
        raise ValueError("После расчёта заказа товара у производителя таблица пуста.")

    output_path = str(Path(cfg.output_dir) / f"Заказ_в_Турцию_{cfg.store_name}_{cfg.run_date:%Y%m%d}.xlsx")
    debug_path = str(Path(cfg.output_dir) / "wb_supplier_order_debug.xlsx")

    info_rows = [
        ["Режим", "Расчёт заказа товара у производителя"],
        ["Дата расчёта", cfg.run_date.strftime("%Y-%m-%d")],
        ["Срок производства/логистики, дней", cfg.supplier_lead_days],
        ["Целевое покрытие после приезда, дней", cfg.supplier_coverage_days],
        ["Дата приезда", (cfg.run_date + timedelta(days=cfg.supplier_lead_days)).strftime("%Y-%m-%d")],
        ["Месяц ABC", cfg.abc_target_month],
        ["Коэффициент по умолчанию", cfg.supplier_default_coeff],
        ["Порог прорыва", cfg.supplier_breakthrough_threshold],
        ["Правило OOS", "Если текущих остатков не хватает до приезда, дефицит до приезда не покрывается; заказ считается только на период после приезда"],
        ["Правило low-turnover", f"Если продаж за 90 дней < {cfg.low_turnover_sales_threshold}, цель после приезда не ниже {cfg.low_turnover_network_stock} шт"],
    ]
    info_df = pd.DataFrame(info_rows, columns=["Параметр", "Значение"])

    with pd.ExcelWriter(output_path, engine="openpyxl") as writer:
        supplier_df.to_excel(writer, index=False, sheet_name="Заказ в Турцию")
        trace_df.to_excel(writer, index=False, sheet_name="Помесячный расчет")
        info_df.to_excel(writer, index=False, sheet_name="Информация")

    with pd.ExcelWriter(debug_path, engine="openpyxl") as writer:
        supplier_df.to_excel(writer, index=False, sheet_name="Заказ в Турцию")
        trace_df.to_excel(writer, index=False, sheet_name="Помесячный расчет")
        region_metrics.to_excel(writer, index=False, sheet_name="RegionMetrics")
        current_stock_df.to_excel(writer, index=False, sheet_name="CurrentStocks")

    style_workbook(Path(output_path))
    style_workbook(Path(debug_path))
    style_supplier_workbook(output_path)
    style_supplier_workbook(debug_path)

    files_to_send = [output_path]
    send_results_to_telegram(cfg, files_to_send)

    log(f"Сохранён supplier-файл: {output_path}")
    log(f"Сохранён supplier-debug: {debug_path}")
    return output_path

def prepare_1c_stocks_map(df_1c_stocks: pd.DataFrame) -> pd.DataFrame:
    df = df_1c_stocks.copy()
    if "Артикул" not in df.columns:
        raise KeyError('В файле "Остатки 1С.xlsx" нет колонки "Артикул".')

    for col in ONE_C_STOCK_COLUMNS:
        if col not in df.columns:
            df[col] = 0

    df["Артикул"] = df["Артикул"].map(normalize_text)
    return df[["Артикул"] + ONE_C_STOCK_COLUMNS].drop_duplicates(subset=["Артикул"])


def resolve_template(storage: S3Storage, cfg: AppConfig, workdir: str) -> str:
    target = Path(workdir) / "Согласование поставки WB.xlsm"
    storage.download_file(cfg.template_key, str(target))
    return str(target)


def pick_sheet_name(store_name: str) -> str:
    name = store_name.strip().upper()
    if "TOPFACE" in name or name == "TF":
        return "ТФ ВБ"
    if "MISS" in name or "TAIS" in name or name == "MT":
        return "МТ ВБ"
    return "ТФ ВБ"


def build_template_dataset(plan_df: pd.DataFrame, stocks_1c_map: pd.DataFrame) -> pd.DataFrame:
    work = plan_df.copy()

    if "Артикул 1С" not in work.columns:
        work["Артикул 1С"] = ""

    missing_article_mask = work["Артикул 1С"].map(normalize_text).eq("")
    if missing_article_mask.any() and "supplierArticle" in work.columns:
        filled_count = int(missing_article_mask.sum())
        work.loc[missing_article_mask, "Артикул 1С"] = work.loc[missing_article_mask, "supplierArticle"].map(normalize_text)
        log(f"Для шаблона поставки заполнены пустые 'Артикул 1С' из supplierArticle: {filled_count:,} строк")

    wide = work.pivot_table(
        index=["supplierArticle", "Артикул 1С", "nmId", "subject"],
        columns="warehouse",
        values="to_supply",
        aggfunc="sum",
        fill_value=0,
    ).reset_index()

    warehouse_cols = [
        c for c in wide.columns
        if c not in ["supplierArticle", "Артикул 1С", "nmId", "subject"]
    ]

    if warehouse_cols:
        wide["Общий итог"] = wide[warehouse_cols].sum(axis=1)
    else:
        wide["Общий итог"] = 0

    stocks_1c_map = stocks_1c_map.rename(columns={"Артикул": "Артикул 1С"})
    out = wide.merge(stocks_1c_map, on="Артикул 1С", how="left")

    out["missing_1c_article"] = (
        out["Артикул 1С"].astype(str).str.strip().eq("")
        | out[ONE_C_STOCK_COLUMNS].isna().all(axis=1)
    )

    for col in ONE_C_STOCK_COLUMNS:
        out[col] = pd.to_numeric(out[col], errors="coerce").fillna(0)

    out = out[out["Артикул 1С"].astype(str).str.strip() != ""].copy()

    if warehouse_cols:
        out["Общий итог"] = out[warehouse_cols].sum(axis=1)
        out = out[out["Общий итог"] > 0].copy()

    return out


def fill_template_file(template_path: str, output_path: str, data_df: pd.DataFrame, cfg: AppConfig) -> str:
    wb = load_workbook(template_path, keep_vba=True)
    ws = wb[pick_sheet_name(cfg.store_name)]

    header_row = 1

    def get_header_map() -> Dict[str, int]:
        return {
            normalize_template_header(ws.cell(header_row, col).value): col
            for col in range(1, ws.max_column + 1)
            if normalize_template_header(ws.cell(header_row, col).value)
        }

    header_map = get_header_map()

    article_1c_col = header_map.get("Артикул 1С") or header_map.get("Артикул 1с")
    if article_1c_col is None:
        raise KeyError(f"Не найдена колонка 'Артикул 1С'. Заголовки шаблона: {list(header_map.keys())}")

    total_col = header_map.get("Общий итог")
    if total_col is None:
        raise KeyError(f"Не найдена колонка 'Общий итог'. Заголовки шаблона: {list(header_map.keys())}")

    one_c_col_map = {
        col_name: header_map[col_name]
        for col_name in ONE_C_STOCK_COLUMNS
        if col_name in header_map
    }

    technical_cols = {"supplierArticle", "Артикул 1С", "nmId", "subject", "Общий итог", "missing_1c_article"}
    source_warehouse_cols = [
        c for c in data_df.columns
        if c not in technical_cols and c not in ONE_C_STOCK_COLUMNS
    ]

    preferred_order = [
        "Коледино",
        "Тула",
        "Электросталь",
        "Казань",
        "Самара (Новосемейкино)",
        "Краснодар",
        "Невинномысск",
        "Волгоград",
        "Рязань (Тюшевское)",
        "Сарапул",
        "Екатеринбург - Перспективная 14",
        "Владимир",
        "Котовск",
        "Воронеж",
        "Склад Шушары",
        "Новосибирск",
    ]
    ordered_warehouses = [w for w in preferred_order if w in source_warehouse_cols]
    ordered_warehouses += [w for w in source_warehouse_cols if w not in ordered_warehouses]

    if total_col > article_1c_col + 1:
        ws.delete_cols(article_1c_col + 1, total_col - article_1c_col - 1)

    header_map = get_header_map()
    total_col = header_map.get("Общий итог")
    if total_col is None:
        raise KeyError("После перестройки не найдена колонка 'Общий итог'")

    if ordered_warehouses:
        ws.insert_cols(article_1c_col + 1, amount=len(ordered_warehouses))

    reverse_template_names = {
        "Самара (Новосемейкино)": "Новосемейкино",
        "Рязань (Тюшевское)": "Рязань",
        "Екатеринбург - Перспективная 14": "Екатеринбург",
        "Склад Шушары": "Склад Шушары",
        "Санкт-Петербург Уткина Заводь": "Склад Шушары",
    }

    for i, wh in enumerate(ordered_warehouses, start=article_1c_col + 1):
        ws.cell(header_row, i, reverse_template_names.get(wh, wh))

    header_map = get_header_map()
    total_col = header_map.get("Общий итог")
    article_1c_col = header_map.get("Артикул 1С") or header_map.get("Артикул 1с")
    one_c_col_map = {
        col_name: header_map[col_name]
        for col_name in ONE_C_STOCK_COLUMNS
        if col_name in header_map
    }

    warehouse_write_map: Dict[str, int] = {}
    for col in range(article_1c_col + 1, total_col):
        header = normalize_template_header(ws.cell(header_row, col).value)
        if not header:
            continue
        internal_name = TEMPLATE_WAREHOUSE_ALIASES.get(header, header)
        warehouse_write_map[internal_name] = col

    template_warehouse_cols = [c for c in warehouse_write_map.keys() if c in data_df.columns]
    if template_warehouse_cols:
        data_df = data_df.copy()
        data_df["template_total"] = data_df[template_warehouse_cols].sum(axis=1)
        data_df = data_df[data_df["template_total"] > 0].copy()

    clear_cols = {article_1c_col, total_col}
    clear_cols.update(warehouse_write_map.values())
    clear_cols.update(one_c_col_map.values())

    for row_idx in range(2, ws.max_row + 1):
        for col_idx in clear_cols:
            ws.cell(row_idx, col_idx).value = None
            ws.cell(row_idx, col_idx).fill = PatternFill(fill_type=None)

    log(f"Строк после фильтрации под шаблон: {len(data_df)}")

    if len(data_df) > ws.max_row - 1:
        raise ValueError(
            f"В шаблоне недостаточно строк. Доступно: {ws.max_row - 1}, нужно: {len(data_df)}"
        )

    red_fill = PatternFill(fill_type="solid", fgColor="FFC7CE")

    for i, (_, row) in enumerate(data_df.iterrows(), start=2):
        ws.cell(i, article_1c_col, row["Артикул 1С"])

        row_total = 0
        for warehouse, col_idx in warehouse_write_map.items():
            value = floor_int(row.get(warehouse, 0))
            ws.cell(i, col_idx, value)
            row_total += value

        ws.cell(i, total_col, row_total)

        for col_name, col_idx in one_c_col_map.items():
            ws.cell(i, col_idx, floor_int(row.get(col_name, 0)))

        if bool(row.get("missing_1c_article", False)):
            for col_idx in range(1, ws.max_column + 1):
                ws.cell(i, col_idx).fill = red_fill

    wb.save(output_path)
    wb.close()
    return output_path


def send_telegram_document(bot_token: str, chat_id: str, file_path: str, caption: str = "") -> None:
    if not bot_token or not chat_id:
        raise ValueError("Не заданы TELEGRAM_BOT_TOKEN или TELEGRAM_CHAT_ID")

    url = f"https://api.telegram.org/bot{bot_token}/sendDocument"
    with open(file_path, "rb") as f:
        files = {"document": (Path(file_path).name, f)}
        data = {"chat_id": chat_id, "caption": caption[:1024]}
        response = requests.post(url, data=data, files=files, timeout=300)

    if response.status_code != 200:
        raise RuntimeError(f"Ошибка отправки в Telegram: {response.status_code} {response.text}")


def send_results_to_telegram(cfg: AppConfig, files: List[str]) -> None:
    if not cfg.send_telegram:
        log("Отправка в Telegram отключена.")
        return

    for file_path in files:
        caption = f"{cfg.store_name} | {cfg.run_date:%Y-%m-%d} | {Path(file_path).name}"
        send_telegram_document(cfg.telegram_bot_token, cfg.telegram_chat_id, file_path, caption)
        log(f"Файл отправлен в Telegram: {file_path}")


def save_debug_files(
    output_dir: str,
    sku_df: pd.DataFrame,
    region_metrics: pd.DataFrame,
    shares_df: pd.DataFrame,
    plan_df: pd.DataFrame,
    current_stock_df: pd.DataFrame,
    filled_template_path: str,
) -> None:
    Path(output_dir).mkdir(parents=True, exist_ok=True)

    debug_path = Path(output_dir) / "wb_supply_debug.xlsx"
    with pd.ExcelWriter(debug_path, engine="openpyxl") as writer:
        sku_df.to_excel(writer, index=False, sheet_name="SKU")
        region_metrics.to_excel(writer, index=False, sheet_name="RegionMetrics")
        shares_df.to_excel(writer, index=False, sheet_name="WarehouseShares")
        current_stock_df.to_excel(writer, index=False, sheet_name="CurrentStocks")
        if not current_stock_df.empty:
            network = (
                current_stock_df.groupby("nmId", as_index=False)
                .agg(
                    network_stock_full=("current_stock_full", "sum"),
                    network_stock_available=("current_stock_available", "sum"),
                )
            )
            network.to_excel(writer, index=False, sheet_name="NetworkStocks")
        plan_df.to_excel(writer, index=False, sheet_name="Plan")

    log(f"Сохранён debug-файл: {debug_path}")
    log(f"Сохранён шаблон: {filled_template_path}")


def main(cfg: AppConfig = CONFIG) -> str:
    Path(cfg.output_dir).mkdir(parents=True, exist_ok=True)

    cfg.calculation_mode = normalize_calculation_mode(cfg.calculation_mode)
    log(
        f"Старт расчёта. mode={cfg.calculation_mode}, store={cfg.store_name}, season_coeff={cfg.season_coeff}, "
        f"run_date={cfg.run_date:%Y-%m-%d}, strategy={cfg.strategy_mode}"
    )

    storage = S3Storage(cfg)

    orders = load_orders(storage, cfg)
    stocks = load_stocks(storage, cfg)
    article_1c_map = load_article_map_1c(storage, cfg)
    stocks_1c_raw = load_1c_stocks(storage, cfg)
    stocks_1c_map = prepare_1c_stocks_map(stocks_1c_raw)
    ratings_map = load_ratings_map(storage, cfg)

    if ratings_map:
        sku_df_tmp = orders[["nmId"]].drop_duplicates().copy()
        sku_df_tmp["review_rating"] = sku_df_tmp["nmId"].map(ratings_map)
        bad_skus = set(
            sku_df_tmp.loc[
                sku_df_tmp["review_rating"].notna()
                & (sku_df_tmp["review_rating"] < cfg.min_review_rating),
                "nmId",
            ].astype(str)
        )
        if bad_skus:
            orders_before = len(orders)
            stocks_before = len(stocks)
            orders = orders[~orders["nmId"].isin(bad_skus)].copy()
            stocks = stocks[~stocks["nmId"].isin(bad_skus)].copy()
            log(f"Исключено SKU по рейтингу отзывов < {cfg.min_review_rating}: {len(bad_skus)}")
            log(f"Удалено строк из заказов по рейтингу: {orders_before - len(orders)}")
            log(f"Удалено строк из остатков по рейтингу: {stocks_before - len(stocks)}")
        else:
            log(f"SKU с рейтингом отзывов < {cfg.min_review_rating} не найдено")

    stocks_1c_local = str(Path(cfg.output_dir) / "Остатки 1С.xlsx")
    storage.download_file(cfg.stocks_1c_key, stocks_1c_local)

    daily_orders = prepare_daily_orders(orders)
    grid = build_daily_grid(daily_orders, cfg)

    current_stock_df_raw, history_dates, per_wh, per_district, latest_stock_date = prepare_stock_presence(stocks)
    if pd.notna(latest_stock_date):
        log(f"Актуальная дата остатков: {latest_stock_date:%Y-%m-%d}")

    current_stock = current_stock_by_warehouse(current_stock_df_raw)
    log(f"Текущих остатков по складам в расчёте: {len(current_stock):,} строк")
    log(f"Сумма текущих остатков по складам (full): {current_stock['current_stock_full'].sum():,.0f}")
    log(f"Сумма текущих остатков по складам (available): {current_stock['current_stock_available'].sum():,.0f}")

    grid = attach_presence_flags(grid, per_wh, per_district, history_dates)
    log(f"GRID SIZE: {len(grid):,}")

    log("Начинаем aggregate_region_metrics...")
    region_metrics = aggregate_region_metrics(grid, cfg)
    log(f"Region metrics рассчитаны: {len(region_metrics):,}")

    if cfg.calculation_mode == "supplier":
        output_path = run_supplier_mode(
            storage=storage,
            cfg=cfg,
            article_1c_map=article_1c_map,
            stocks_1c_raw=stocks_1c_raw,
            current_stock_df=current_stock,
            region_metrics=region_metrics,
            stocks_1c_local=stocks_1c_local,
        )
        log("Готово")
        return output_path

    sku_df = choose_final_daily_demand(region_metrics, cfg)
    shares_df = build_warehouse_shares(region_metrics)
    shares_df = apply_strategy(shares_df, cfg)

    if ratings_map:
        sku_df["review_rating"] = sku_df["nmId"].map(ratings_map)

    plan_df = calculate_supply_plan(sku_df, shares_df, current_stock, article_1c_map, cfg)
    if plan_df.empty:
        raise ValueError("После расчёта план поставки пуст.")

    template_data = build_template_dataset(plan_df, stocks_1c_map)
    log(f"Строк для заполнения шаблона: {len(template_data):,}")
    if template_data.empty:
        missing_articles = int(plan_df["Артикул 1С"].map(normalize_text).eq("").sum()) if "Артикул 1С" in plan_df.columns else 0
        log(f"⚠️ Шаблон пустой: в плане строк={len(plan_df):,}, строк без 'Артикул 1С'={missing_articles:,}")

    with tempfile.TemporaryDirectory() as tmpdir:
        template_path = resolve_template(storage, cfg, tmpdir)
        output_path = str(Path(cfg.output_dir) / f"Согласование поставки WB_{cfg.store_name}_{cfg.run_date:%Y%m%d}.xlsm")
        fill_template_file(template_path, output_path, template_data, cfg)

    save_debug_files(cfg.output_dir, sku_df, region_metrics, shares_df, plan_df, current_stock, output_path)

    if cfg.upload_result_to_s3:
        result_key = f"Отчёты/Поставки/{cfg.store_name}/{Path(output_path).name}"
        storage.upload_file(output_path, result_key)
        log(f"Результат загружен в Object Storage: {result_key}")

    files_to_send = [
        output_path,
        str(Path(cfg.output_dir) / "wb_supply_debug.xlsx"),
        stocks_1c_local,
    ]
    send_results_to_telegram(cfg, files_to_send)

    log("Готово")
    return output_path



def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(description="WB supply calculator")
    parser.add_argument("--mode", choices=["supply", "warehouse", "supplier"], default=None, help="supply = расчёт поставки по складам, supplier = расчёт заказа у производителя")
    parser.add_argument("--run-date", default=None, help="Дата расчёта в формате YYYY-MM-DD")
    parser.add_argument("--season-coeff", type=float, default=None, help="Коэффициент сезонности для warehouse-режима")
    parser.add_argument("--supplier-default-coeff", type=float, default=None, help="Коэффициент по умолчанию для supplier-режима, если SKU нет в плане")
    parser.add_argument("--supplier-lead-days", type=int, default=None, help="Срок приезда заказа от производителя")
    parser.add_argument("--supplier-coverage-days", type=int, default=None, help="Покрытие после приезда")
    parser.add_argument("--supplier-breakthrough-threshold", type=float, default=None, help="Порог для статуса Прорыв")
    parser.add_argument("--abc-target-month", default=None, help="Месяц ABC в формате YYYY-MM")
    parser.add_argument("--strategy-mode", choices=["default", "economy"], default=None, help="Стратегия распределения для warehouse-режима")
    return parser


def build_cfg_from_args(args: argparse.Namespace) -> AppConfig:
    cfg = AppConfig()
    if args.mode:
        cfg.calculation_mode = normalize_calculation_mode(args.mode)
    if args.run_date:
        cfg.run_date = datetime.strptime(args.run_date, "%Y-%m-%d")
    if args.season_coeff is not None:
        cfg.season_coeff = float(args.season_coeff)
    if args.supplier_default_coeff is not None:
        cfg.supplier_default_coeff = float(args.supplier_default_coeff)
    if args.supplier_lead_days is not None:
        cfg.supplier_lead_days = int(args.supplier_lead_days)
    if args.supplier_coverage_days is not None:
        cfg.supplier_coverage_days = int(args.supplier_coverage_days)
    if args.supplier_breakthrough_threshold is not None:
        cfg.supplier_breakthrough_threshold = float(args.supplier_breakthrough_threshold)
    if args.abc_target_month:
        cfg.abc_target_month = args.abc_target_month
    if args.strategy_mode:
        cfg.strategy_mode = args.strategy_mode
    return cfg


if __name__ == "__main__":
    args = build_parser().parse_args()
    main(build_cfg_from_args(args))
